def words_with_n_vowels(sentence, n):
    vowels = "aeiouAEIOU"
    result = []
    for word in sentence.split():
        count = 0
        for c in word:
            if c in vowels:
                count += 1
        if count >= n:
            result.append(word)
    return result

unit_tests:
import unittest

class TestSolution(unittest.TestCase):
    def test_basic_example(self):
        self.assertEqual(words_with_n_vowels("hello world", 2), ["hello"])

    def test_multiple_matches(self):
        self.assertEqual(words_with_n_vowels("beautiful day outside", 3), ["beautiful", "outside"])

    def test_no_vowels(self):
        self.assertEqual(words_with_n_vowels("rhythm myth", 1), [])

    def test_hidden_empty_string(self):
        self.assertEqual(words_with_n_vowels("", 1), [])

    def test_hidden_n_zero(self):
        self.assertEqual(words_with_n_vowels("fly by cry", 0), ["fly", "by", "cry"])

    def test_hidden_all_words_match(self):
        self.assertEqual(words_with_n_vowels("The quick brown fox", 1), ["The", "quick", "brown", "fox"])

    def test_hidden_single_char(self):
        self.assertEqual(words_with_n_vowels("a", 1), ["a"])

    def test_hidden_uppercase_vowels(self):
        self.assertEqual(words_with_n_vowels("Education is Important", 4), ["Education"])

    def test_hidden_all_vowels_word(self):
        self.assertEqual(words_with_n_vowels("aaa eee iii", 3), ["aaa", "eee", "iii"])

    def test_hidden_high_threshold(self):
        self.assertEqual(words_with_n_vowels("hello world", 10), [])

if __name__ == '__main__':
    unittest.main()
